import { useState } from "react";
import axios from "axios";

function App() {
  const [file, setFile] = useState(null);
  const [result, setResult] = useState(null);
  const [feedback, setFeedback] = useState("");
  const [loading, setLoading] = useState(false);

  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
  };

  const handlePredict = async () => {
    if (!file) return alert("Upload audio first");

    const formData = new FormData();
    formData.append("file", file);

    try {
      setLoading(true);
      const res = await axios.post(
        "http://127.0.0.1:8000/predict",
        formData
      );
      setResult(res.data);
      setLoading(false);
    } catch (err) {
      console.error(err);
      alert("Backend error");
      setLoading(false);
    }
  };

  const sendFeedback = async () => {
    await axios.post("http://127.0.0.1:8000/feedback", {
      prediction: result.prediction,
      feedback: feedback,
    });
    alert("Feedback saved");
    setFeedback("");
  };

  return (
    <div style={page}>
      {/* BRAND */}
      <h1 style={brand}>COGNIFY</h1>

      {/* TAGLINE */}
      <p style={subtitle}>
        Understand your lectures better — detect cognitive load, simplify learning, and enhance retention with AI-powered insights.
      </p>

      {/* UPLOAD CARD */}
      <div style={card}>
        <h3 style={section}>Upload Lecture Audio</h3>

        <input type="file" onChange={handleFileChange} style={fileInput} />

        <button style={btn} onClick={handlePredict}>
          Analyze Lecture
        </button>

        {loading && <p style={loadingText}>Processing audio...</p>}
      </div>

      {/* RESULT CARD */}
      {result && (
        <div style={card}>
          <h2 style={prediction}>
            Prediction: {result.prediction.toUpperCase()}
          </h2>

          {/* PROBABILITY */}
          <div style={probRow}>
            <div style={probBox}>
              Low <br /> {result.probability.low.toFixed(2)}
            </div>
            <div style={probBox}>
              Medium <br /> {result.probability.medium.toFixed(2)}
            </div>
            <div style={probBox}>
              High <br /> {result.probability.high.toFixed(2)}
            </div>
          </div>

          {/* SUMMARY */}
          <h3 style={section}>Lecture Summary</h3>
          <p style={text}>{result.summary}</p>

          {/* QUIZ */}
          <h3 style={section}>Generated Quiz</h3>
          <ul>
            {result.quiz.map((q, i) => (
              <li key={i} style={text}>{q}</li>
            ))}
          </ul>

          {/* FEEDBACK */}
          <h3 style={section}>Your Feedback</h3>
          <input
            value={feedback}
            onChange={(e) => setFeedback(e.target.value)}
            placeholder="Share your learning experience..."
            style={input}
          />

          <button style={btn} onClick={sendFeedback}>
            Submit Feedback
          </button>
        </div>
      )}
    </div>
  );
}

/* ================= STYLES ================= */

const page = {
  minHeight: "100vh",
  background: "linear-gradient(135deg, #0f2027, #203a43, #2c5364)",
  padding: "40px",
  fontFamily: "Segoe UI",
};

const brand = {
  textAlign: "center",
  color: "#00d4ff",
  fontSize: "32px",   // 👈 bigger COGNIFY
  letterSpacing: "4px",
  marginBottom: "10px",
};

const subtitle = {
  textAlign: "center",
  color: "#aaaaaa",
  marginTop: "10px",
  marginBottom: "30px",
  maxWidth: "700px",
  marginLeft: "auto",
  marginRight: "auto",
};

const card = {
  background: "rgba(255,255,255,0.05)",
  backdropFilter: "blur(12px)",
  borderRadius: "15px",
  padding: "25px",
  margin: "20px auto",
  maxWidth: "750px",
  boxShadow: "0 10px 30px rgba(0,0,0,0.4)",
  border: "1px solid rgba(255,255,255,0.1)",
};

const section = {
  color: "#00d4ff",
  marginBottom: "10px",
};

const btn = {
  marginTop: "15px",
  padding: "10px 20px",
  background: "linear-gradient(90deg, #00c6ff, #0072ff)",
  border: "none",
  color: "white",
  borderRadius: "6px",
  cursor: "pointer",
};

const probRow = {
  display: "flex",
  justifyContent: "space-between",
  margin: "15px 0",
};

const probBox = {
  background: "rgba(255,255,255,0.1)",
  padding: "12px",
  borderRadius: "8px",
  color: "#fff",
  textAlign: "center",
  width: "30%",
};

const input = {
  padding: "10px",
  width: "70%",
  marginRight: "10px",
  borderRadius: "5px",
  border: "none",
};

const fileInput = {
  marginTop: "10px",
  color: "white",
};

const text = {
  color: "#e0e0e0",
};

const prediction = {
  color: "#00ff9f",
};

const loadingText = {
  color: "#00d4ff",
};

export default App;
